[CmdletBinding(SupportsShouldProcess=$true)]
param([Parameter(Mandatory)][string]$ProcessName,[string]$ExecutablePath,[switch]$TerminateHungProcess,[switch]$ClearCrashDumps,[switch]$ResetWer,[switch]$RunSystemRepair,[string]$OutputPath="$env:USERPROFILE\Desktop\AppCrashRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($TerminateHungProcess-or$ClearCrashDumps-or$ResetWer-or$RunSystemRepair)){throw'Choose at least one repair action.'}
Get-WinEvent -FilterHashtable @{LogName='Application';StartTime=(Get-Date).AddDays(-3)} -ErrorAction SilentlyContinue|Where-Object Message-match[regex]::Escape($ProcessName)|Select -First 100|Export-Clixml (Join-Path $OutputPath 'crashes-before.xml')
if($TerminateHungProcess){$p=Get-Process $ProcessName -ErrorAction SilentlyContinue;if($p-and$PSCmdlet.ShouldProcess($ProcessName,'Stop hung process')){$p|Stop-Process -Force;L'Process stopped.'}}
if($ClearCrashDumps){$paths=@("$env:LOCALAPPDATA\CrashDumps","$env:ProgramData\Microsoft\Windows\WER\ReportArchive","$env:ProgramData\Microsoft\Windows\WER\ReportQueue");foreach($x in $paths){if(Test-Path $x){Get-ChildItem $x -Recurse -File -ErrorAction SilentlyContinue|Where-Object Name-like"*$ProcessName*"|ForEach-Object{if($PSCmdlet.ShouldProcess($_.FullName,'Remove matching crash artefact')){Remove-Item $_.FullName -Force}}}};L'Crash artefacts processed.'}
if($ResetWer-and$PSCmdlet.ShouldProcess('Windows Error Reporting','Restart service')){Restart-Service WerSvc -Force -ErrorAction SilentlyContinue;L'WER service restarted.'}
if($RunSystemRepair-and$PSCmdlet.ShouldProcess('Windows image','Run DISM and SFC')){dism /Online /Cleanup-Image /RestoreHealth|Tee-Object -FilePath $Log -Append;sfc /scannow|Tee-Object -FilePath $Log -Append;L'System repair completed.'}
if($ExecutablePath-and(Test-Path $ExecutablePath)-and$PSCmdlet.ShouldProcess($ExecutablePath,'Launch application for verification')){Start-Process $ExecutablePath;Start-Sleep 5;Get-Process $ProcessName -ErrorAction SilentlyContinue|Export-Clixml (Join-Path $OutputPath 'process-after.xml')};L'Repair workflow finished.'